ValidationRule.errorConditionFormula:
AND(
    $Profile.Name <> "System Administrator",
    NOT(ISNEW()),
    TEXT(Approval_Status__c) = "Approved by Level 2",
    IF(
        OR($Profile.Name = "CP Access", $Profile.Name = "CP Billing Access"),
        /* Loophole: Only block these profiles if they try to change something OTHER than the legacy field */
        NOT(ISCHANGED(Legacy_booking_treated__c)),
        /* Strict Lock: Block all other profiles from changing anything at all */
        TRUE
    )
)
